import React, { useState, useEffect } from "react";
import "./EMR.css";

export default function EMR() {
  const [tab, setTab] = useState("notes");

  const [vitals, setVitals] = useState({
    hr: "",
    sys: "",
    dia: "",
    rr: "",
    spo2: "",
    temp: ""
  });

  const [redFlags, setRedFlags] = useState({
    chestPain: false,
    hypoxia: false,
    trauma: false,
    seizure: false
  });
  // ================= PATIENT HEADER =================
const [patientInfo, setPatientInfo] = useState({
  name: "",
  age: "",
  mrn: "",
  encounter: "",
  allergies: ""
});

// ================= MEDICATION ORDER =================
const [medOrder, setMedOrder] = useState({
  medication: "",
  dosage: "",
  priority: "",
  startDate: ""
});

  // ✅ default on load
  const [aiLevel, setAiLevel] = useState("LEVEL 5 – NON-URGENT");
  const [triage, setTriage] = useState("LEVEL 5");

  // ================= AI TRIAGE LOGIC =================
  useEffect(() => {
    const { hr, sys, dia, rr, spo2, temp } = vitals;

    const anyValue =
      hr || sys || dia || rr || spo2 || temp ||
      Object.values(redFlags).some(v => v);

    if (!anyValue) {
      setAiLevel("LEVEL 5 – NON-URGENT");
      setTriage("LEVEL 5");
      return;
    }

    let level = "LEVEL 5 – NON-URGENT";

    // 🔴 LEVEL 1 – CRITICAL
    if (
      Number(spo2) > 0 && Number(spo2) < 90 ||
      Number(hr) > 130 ||
      Number(sys) > 0 && Number(sys) < 90 ||
      redFlags.seizure ||
      redFlags.trauma
    ) {
      level = "LEVEL 1 – CRITICAL";
    }

    // 🟠 LEVEL 2 – EMERGENT
    else if (
      redFlags.chestPain ||
      redFlags.hypoxia ||
      Number(temp) >= 39 ||
      Number(rr) > 25
    ) {
      level = "LEVEL 2 – EMERGENT";
    }

    // 🟡 LEVEL 3 – URGENT
    else if (
      Number(hr) > 100 ||
      Number(rr) > 20 ||
      Number(temp) > 38
    ) {
      level = "LEVEL 3 – URGENT";
    }

    // 🟢 LEVEL 4 – SEMI-URGENT
    else {
      level = "LEVEL 4 – SEMI-URGENT";
    }

    setAiLevel(level);
    setTriage(level.split("–")[0].trim());

  }, [vitals, redFlags]);

  return (
    <div className="emr-wrapper">

      {/* ================= TABS ================= */}
      <div className="tabs">
        <button
          className={tab === "notes" ? "active" : ""}
          onClick={() => setTab("notes")}
        >
          Clinical Notes
        </button>

        <button
          className={tab === "vitals" ? "active" : ""}
          onClick={() => setTab("vitals")}
        >
          Vitals
        </button>

         <button
  className={tab === "CPOE" ? "active" : ""}
  onClick={() => setTab("")}
>
  Medications
</button>
 

      </div>
     

      {/* ================= CLINICAL NOTES ================= */}
      {tab === "notes" && (
        <div className="card">
          <label>Chief Complaint</label>
          <input />

          <label>History of Present Illness</label>
          <textarea />

          <label>Assessment</label>
          <textarea />

          <label>Plan</label>
          <textarea />
        </div>
      )}

      {/* ================= VITALS ================= */}
      {tab === "vitals" && (
        <div className="card">

          <h3>Vital Signs</h3>

          <div className="grid">
            <input placeholder="Heart Rate 60–100 bpm"
              onChange={e => setVitals({ ...vitals, hr: e.target.value })} />

            <input placeholder="BP Systolic 90–120 mmHg"
              onChange={e => setVitals({ ...vitals, sys: e.target.value })} />

            <input placeholder="BP Diastolic 60–80 mmHg"
              onChange={e => setVitals({ ...vitals, dia: e.target.value })} />

            <input placeholder="Respiratory Rate 12–20 /min"
              onChange={e => setVitals({ ...vitals, rr: e.target.value })} />

            <input placeholder="SpO₂ 95–100 %"
              onChange={e => setVitals({ ...vitals, spo2: e.target.value })} />

            <input placeholder="Temperature 36.5–37.5 °C"
              onChange={e => setVitals({ ...vitals, temp: e.target.value })} />
          </div>

          {/* ===== RED FLAGS ===== */}
          <h3>Red Flags Detected</h3>
          <div className="checks">
            {Object.keys(redFlags).map((key) => (
              <label key={key}>
                <input
                  type="checkbox"
                  checked={redFlags[key]}
                  onChange={() =>
                    setRedFlags({ ...redFlags, [key]: !redFlags[key] })
                  }
                />
                {key}
              </label>
            ))}
          </div>

          {/* ===== AI RESULT ===== */}
          <div className="ai-box">
            <h3>AI Suggested Level</h3>
            <strong>{aiLevel}</strong>
          </div>

          {/* ===== TRIAGE BUTTONS WITH LABEL ===== */}
          <h3>Triage Level</h3>

          <div className="triage">
            <button className={triage === "LEVEL 1" ? "active red" : "red"}>
              LEVEL 1 – CRITICAL
            </button>

            <button className={triage === "LEVEL 2" ? "active orange" : "orange"}>
              LEVEL 2 – EMERGENT
            </button>

            <button className={triage === "LEVEL 3" ? "active yellow" : "yellow"}>
              LEVEL 3 – URGENT
            </button>

            <button className={triage === "LEVEL 4" ? "active green" : "green"}>
              LEVEL 4 – SEMI-URGENT
            </button>

            <button className={triage === "LEVEL 5" ? "active blue" : "blue"}>
              LEVEL 5 – NON-URGENT
            </button>
          </div>

          {/* ===== ISOLATION ===== */}
          <h3>Isolation</h3>
          <div className="checks">
            <label><input type="checkbox" /> Droplet</label>
            <label><input type="checkbox" /> Contact</label>
            <label><input type="checkbox" /> None</label>
          </div>

          <label>Nurse Name</label>
          <input placeholder="Enter nurse name" />

        </div>
      )}

      {/* ================= FOOTER ================= */}
      <div className="footer-btns">
        <button className="draft">Save Draft</button>
        <button className="complete">Complete Visit</button>
      </div>
      {/* ================= MEDICATION ================= */}
{tab === "medication" && (
  <div className="card">

    {/* ===== PATIENT HEADER ===== */}
    <div className="patient-header">

      <input
        placeholder="Patient Name"
        onChange={(e) =>
          setPatientInfo({ ...patientInfo, name: e.target.value })
        }
      />

      <input
        placeholder="Age"
        onChange={(e) =>
          setPatientInfo({ ...patientInfo, age: e.target.value })
        }
      />

      <input
        placeholder="MRN"
        onChange={(e) =>
          setPatientInfo({ ...patientInfo, mrn: e.target.value })
        }
      />

      <input
        placeholder="Encounter ID"
        onChange={(e) =>
          setPatientInfo({ ...patientInfo, encounter: e.target.value })
        }
      />

      <input
        placeholder="Allergies"
        onChange={(e) =>
          setPatientInfo({ ...patientInfo, allergies: e.target.value })
        }
      />

    </div>

    {/* ===== ADD MEDICATION ORDER ===== */}
    <h3>Add Medication Order</h3>

    <div className="med-grid">

      <input
        placeholder="Medication (e.g. Atorvastatin 20mg)"
        onChange={(e) =>
          setMedOrder({ ...medOrder, medication: e.target.value })
        }
      />

      <input
        placeholder="Dosage (e.g. Once Daily)"
        onChange={(e) =>
          setMedOrder({ ...medOrder, dosage: e.target.value })
        }
      />

      <input
        placeholder="Priority (Routine / Urgent)"
        onChange={(e) =>
          setMedOrder({ ...medOrder, priority: e.target.value })
        }
      />

      <input
        type="date"
        onChange={(e) =>
          setMedOrder({ ...medOrder, startDate: e.target.value })
        }
      />

    </div>

    {/* ===== CDS ALERT ===== */}
    <div className="cds-alert">
      ⚠ Drug Interaction Alert: Check allergies & drug interactions.
    </div>

    {/* ===== ACTION BUTTONS ===== */}
    <div className="med-actions">
      <button className="draft">Cancel</button>
      <button className="complete">Add Order</button>
    </div>

    {/* ===== ACTIVE ORDERS TABLE ===== */}
    <h3>Active Orders</h3>

    <table className="med-table">
      <thead>
        <tr>
          <th>Medication</th>
          <th>Priority</th>
          <th>Status</th>
          <th>Actions</th>
        </tr>
      </thead>

      <tbody>
        <tr>
          <td>{medOrder.medication || "—"}</td>
          <td>{medOrder.priority || "—"}</td>
          <td>ACTIVE</td>
          <td>
            <button>View</button>
            <button>Edit</button>
            <button>Cancel</button>
          </td>
        </tr>
      </tbody>
    </table>

  </div>
)}

    </div>
  );
}
